import heapq
import sys

def input():
    return sys.stdin.readline().rstrip()

n, m = map(int, input().split())
graph = [[] for _ in range(n + 1)]
for _ in range(m):
    a, b, t = map(int, input().split())
    graph[a].append((b, t))
    graph[b].append((a, t))

INF = 10 ** 18

def dijkstra(start):
    dist = [INF] * (n + 1)
    first = [0] * (n + 1)
    dist[start] = 0
    pq = [(0, start)]

    while pq:
        cur_dist, cur = heapq.heappop(pq)
        if cur_dist != dist[cur]:
            continue
        for nxt, weight in graph[cur]:
            new_dist = cur_dist + weight
            if new_dist < dist[nxt]:
                dist[nxt] = new_dist
                first[nxt] = nxt if cur == start else first[cur]
                heapq.heappush(pq, (new_dist, nxt))

    return first

for start in range(1, n + 1):
    first = dijkstra(start)
    row = []
    for target in range(1, n + 1):
        if start == target:
            row.append('-')
        else:
            row.append(str(first[target]))
    print(' '.join(row))

