        // 마을 순서대로 정렬합니다 -> 오름차순
        Collections.sort(village);
        long half = (sum_cnt + 1) / 2; 

        // 1번 마을부터  인구수를 더해가며 중간 값 이상이 되면 그곳에 우체국을 설치합니다
        long sum = 0;
        for(int i = 0;i < village.size();i++) {
            sum += village.get(i).cnt;
            if(sum >= half) {
                System.out.println(village.get(i).loc);
                break;
            }
        }
    }

