    for(int i=1;i< n;i++) {
        int a, b; cin >> a >> b;
        graph[a].push_back(b);
        graph[b].push_back(a);
    }

    dfs(1, 1);
    trace(1, 1);
    cout << max(DP[1][0], DP[1][1]) << '\n';
