    for(int i=1;i<n;i++) {
        int a, b; cin >> a >> b;
        graph[a].emplace_back(b);
        graph[b].emplace_back(a);
    }

    dfs(1, 1);
    cout << min(go(1, 0), go(1, 1));

    return 0;
}

