        }
        for (int i = 0; i < 19; i++) {
            for (int j = 0; j < 19; j++) {
                int cur = board[i][j];
                if(cur > 0) {
                    for (int d = 0; d < 4; d++) {
                        int nx = i + dx[d];
                        int ny = j + dy[d];
                        if(!isPossible(nx, ny)) continue;
                        if(board[nx][ny] == cur) {
                            var a = checkFirst(nx, ny, cur, d) + 1;
