// 문제에서 주어진 힌트를 그대로 구현하였습니다.

public class Main {
    static int[] subtreesize, parent;
    static ArrayList<Integer>[] tree, list;

    public static void main(String[] args) throws IOException {
        FastReader rd = new FastReader();

        int N = rd.nextInt();
        int R = rd.nextInt();
        int Q = rd.nextInt();

        tree = new ArrayList[N + 1];
        list = new ArrayList[N + 1];
        subtreesize = new int[N + 1];
        parent = new int[N + 1];

        for(int i = 0;i <= N;i++) {
            tree[i] = new ArrayList<Integer>();
            list[i] = new ArrayList<Integer>();
        }

        for(int i = 0;i < N - 1;i++) {
            int U = rd.nextInt();
            int V = rd.nextInt();
            list[U].add(V);
            list[V].add(U);
        }

        // 문제에 주어진 힌트
        makeTree(R, -1);
        countSubtreeNodes(R);

        for(int i = 0;i < Q;i++) {
            int U = rd.nextInt();
            System.out.println(subtreesize[U]);
        }
    }

    // 입력받은 list를 토대로 트리를 만듭니다.
    static void makeTree(int curNode, int p) {
        for(int node : list[curNode]) {
            if(node != p) {
                tree[curNode].add(node);
                parent[node] = curNode;
                makeTree(node, curNode);
            }
        }
    }

    // dp와 재귀호출로 서브트리크기를 센다.
    static void countSubtreeNodes(int curNode) {
        // 자신도 size에 포함하기 때문에 1부터 시작
        subtreesize[curNode] = 1;
        for(int node : tree[curNode]) {
            countSubtreeNodes(node);
            subtreesize[curNode] += subtreesize[node];
        }
    }

    static class FastReader {
        BufferedReader br;
        StringTokenizer st;

        public FastReader() {
            br = new BufferedReader(new InputStreamReader(System.in));
        }

        String next() {
            while(st == null || !st.hasMoreElements()) {
                try {
                    st = new StringTokenizer(br.readLine());
                }
                catch (IOException e) {
                    e.printStackTrace();
                }
            }
            return st.nextToken();
        }

        int nextInt() { return Integer.parseInt(next()); }
        String nextLine() {
            String str = "";
            try {
                str = br.readLine();
            }
            catch (IOException e) {
                e.printStackTrace();
            }
            return str;
        }
    }
