void spread() {
    vector<vector<int>> tmp = Map;
    for(int i=0;i<N;i++) {
        for(int j=0;j<M;j++) {
            if(tmp[i][j] == 0) continue;
            int div = tmp[i][j] / 5;
            for(int k=0;k<4;k++) {
                int qy = i + dy[k];
                int qx = j + dx[k];
                if((qy == Y[0] || qy == Y[1]) && qx == 0) continue;
                if(inrange(qy, qx)) {
                    Map[i][j] -= div;
                    Map[qy][qx] += div;
                }
            }
        }
    }
}

void air() {
    vector<vector<int>> used(N, vector<int>(M));
    int y = Y[0];
