        int nextx = x + dx[UP[dir]];
        if(0 <= nexty && nexty <= Y[0] && 0 <= nextx && nextx < M && used[nexty][nextx] == 0) {
            used[nexty][nextx] = 1;
            Map[y][x] = Map[nexty][nextx];
            y = nexty;
            x = nextx;
        }
        else dir ++;
    }
    y = Y[1];
    x = 0;
